package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import com.example.sharehandler.databinding.ActivityShareBinding

class ShareActivity : AppCompatActivity() {

    private lateinit var binding: ActivityShareBinding

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        binding = ActivityShareBinding.inflate(layoutInflater)
        setContentView(binding.root)

        handleIncomingShare()
    }

    private fun handleIncomingShare() {
        if (intent?.action == Intent.ACTION_SEND || intent?.action == Intent.ACTION_SEND_MULTIPLE) {
            intent.extras?.let { extras ->
                if (extras.containsKey(Intent.EXTRA_TEXT)) {
                    val sharedText = extras.getString(Intent.EXTRA_TEXT)
                    if (sharedText?.startsWith("http") == true) {
                        processSharedUrl(sharedText)
                    }
                }
                if (extras.containsKey(Intent.EXTRA_STREAM)) {
                    val imageUri: Uri? = extras.getParcelable(Intent.EXTRA_STREAM)
                    imageUri?.let {
                        processSharedImage(it)
                    }
                }
            }
        }
    }

    private fun processSharedUrl(url: String) {
        Toast.makeText(this, "Received URL: $url", Toast.LENGTH_SHORT).show()
    }

    private fun processSharedImage(imageUri: Uri) {
        Toast.makeText(this, "Received Image URI: $imageUri", Toast.LENGTH_SHORT).show()
    }
}